const webhookBody = $('Konfiguration').first().json;
const phase = webhookBody.phase;
const matchId = webhookBody.match_id;
const style = webhookBody.style ?? 'standard';

const match = $('Get Match').first().json;
// Partner-API gibt teamHomeId/teamAwayId als IDs zurück – Namen über Teams holen falls verfügbar
const homeTeamId = match.teamHomeId;
const awayTeamId = match.teamAwayId;
const homeScore = match.teamHomeScore ?? 0;
const awayScore = match.teamAwayScore ?? 0;
const competition = match.competitionId ?? '';

// Team-Namen aus api-sports Statistics-Response holen
const stats = $('Get Statistics').first().json.response ?? [];
const homeTeam = stats[0]?.team?.name ?? 'Heimteam';
const awayTeam = stats[1]?.team?.name ?? 'Auswärtsteam';

const events = $('Get Events').first().json.response ?? [];
const playerTeams = $('Get Players').first().json.response ?? [];

const maxMinute = phase === 'FirstHalfBreak' ? 45 : 999;
const goals = events.filter(e => e.type === 'Goal' && (e.time?.elapsed ?? 0) <= maxMinute);
const cards = events.filter(e => e.type === 'Card' && (e.time?.elapsed ?? 0) <= maxMinute);
const injuries = events.filter(e => e.detail === 'Injury' && (e.time?.elapsed ?? 0) <= maxMinute);
const subs = events.filter(e => e.type === 'subst' && (e.time?.elapsed ?? 0) <= maxMinute);

const homeStats = stats[0]?.statistics ?? [];
const awayStats = stats[1]?.statistics ?? [];
const getStat = (arr, name) => arr.find(s => s.type === name)?.value ?? '–';

const allPlayers = playerTeams.flatMap(t => t.players ?? []);
const topPlayers = allPlayers
  .filter(p => p.statistics?.[0]?.games?.rating)
  .sort((a, b) => parseFloat(b.statistics[0].games.rating) - parseFloat(a.statistics[0].games.rating))
  .slice(0, 3)
  .map(p => `${p.player.name} (${parseFloat(p.statistics[0].games.rating).toFixed(1)})`);

const homeGoalsCount = goals.filter(g => g.team.id === stats[0]?.team?.id).length;
const awayGoalsCount = goals.filter(g => g.team.id === stats[1]?.team?.id).length;
const scoreDisplay = phase === 'FirstHalfBreak'
  ? `${homeGoalsCount}:${awayGoalsCount} (Halbzeit)`
  : `${homeScore}:${awayScore} (Endstand)`;

const phaseLabel = {
  FirstHalfBreak: 'Halbzeitbericht',
  SecondHalfBreak: 'Bericht zur Verlängerungspause',
  After: 'Spielbericht',
  ExtraFirstHalf: 'Bericht nach erster Verlängerungshälfte',
}[phase] ?? 'Bericht';

const goalLines = goals.length > 0
  ? goals.map(g => {
      const extra = g.detail === 'Penalty' ? ' [Elfmeter]' : g.detail === 'Own Goal' ? ' [Eigentor]' : '';
      const assist = g.assist?.name ? ` (Assist: ${g.assist.name})` : '';
      return `  ${g.time.elapsed}' ${g.player.name}${extra}${assist} — ${g.team.name}`;
    }).join('\n')
  : '  Kein Tor';

const cardLines = cards.length > 0
  ? cards.map(c => `  ${c.time.elapsed}' ${c.player.name} – ${c.detail} (${c.team.name})`).join('\n')
  : '  Keine';

const injurySection = injuries.length > 0
  ? `\nVERLETZUNGEN:\n${injuries.map(i => `  ${i.time.elapsed}' ${i.player.name} (${i.team.name})`).join('\n')}`
  : '';

const subNote = subs.length >= 4 ? `\n(${subs.length} Auswechslungen)` : '';

const prompt = `Du bist Liveticker-Redakteur für Eintracht Frankfurt. Schreibe einen ${phaseLabel} (2–3 lebhafte Sätze auf Deutsch, direkte Fansprache).

SPIEL: ${homeTeam} vs ${awayTeam}
SPIELSTAND: ${scoreDisplay}

TORE:\n${goalLines}

KARTEN:\n${cardLines}${injurySection}${subNote}

STATISTIKEN (${homeTeam} vs ${awayTeam}):
Ballbesitz: ${getStat(homeStats, 'Ball Possession')} vs ${getStat(awayStats, 'Ball Possession')}
Schüsse gesamt: ${getStat(homeStats, 'Total Shots')} vs ${getStat(awayStats, 'Total Shots')}
Schüsse aufs Tor: ${getStat(homeStats, 'Shots on Goal')} vs ${getStat(awayStats, 'Shots on Goal')}
xG: ${getStat(homeStats, 'expected_goals')} vs ${getStat(awayStats, 'expected_goals')}
Ecken: ${getStat(homeStats, 'Corner Kicks')} vs ${getStat(awayStats, 'Corner Kicks')}
Fouls: ${getStat(homeStats, 'Fouls')} vs ${getStat(awayStats, 'Fouls')}
Pässe: ${getStat(homeStats, 'Total passes')} (${getStat(homeStats, 'Passes %')}) vs ${getStat(awayStats, 'Total passes')} (${getStat(awayStats, 'Passes %')})

BESTE SPIELER: ${topPlayers.join(', ') || '–'}

Stil: ${style}. Keine reine Statistikaufzählung — interpretiere die Zahlen. Besondere Ereignisse (Verletzungen, Karten) erwähnen.`;

return [{ json: { prompt, match_id: matchId, phase, style } }];

const text = $('OpenRouter').first().json.choices?.[0]?.message?.content?.trim() ?? '';
const { match_id, phase } = $('Build Prompt').first().json;

const phaseMap = {
  FirstHalfBreak: 'FirstHalfBreak',
  After: 'After',
  ExtraFirstHalf: 'ExtraFirstHalf',
  SecondHalfBreak: 'SecondHalfBreak'
};

return [{
  json: {
    matchId: match_id,
    body: {
      sourceId: `summary-${match_id}-${phase}`,
      sport: 'Football',
      position: phase === 'FirstHalfBreak' ? 45 : 90,
      time: phase === 'FirstHalfBreak' ? 45 : 90,
      timeAdditional: 0,
      description: text,
      imageUrl: null,
      videoUrl: null,
      pushTitle: null,
      pushDescription: null,
      pushImageSrc: null,
      embedHtml: null,
      liveTickerPhaseType: phaseMap[phase] ?? 'After',
      liveTickerEventType: 'PhaseChange',
      players: []
    }
  }
}];

